import os

def create_files():
    files = {
        "backend/app/controllers/qr_controller.py": "from fastapi import APIRouter, Depends, UploadFile, File, Form, HTTPException\nfrom sqlalchemy.ext.asyncio import AsyncSession\nfrom app.database.session import get_db\nfrom app.exceptions.custom import DomainException\nfrom app.models.scan import Scan\nimport re\nimport mimetypes\n\nrouter = APIRouter()\n\nMAX_FILE_SIZE = 5 * 1024 * 1024 # 5 MB\nALLOWED_MIMES = ['image/jpeg', 'image/png', 'image/webp']\n\n@router.post(\"/api/scan/qr\")\nasync def scan_qr(\n    extracted_url: str = Form(...),\n    file: UploadFile = File(None),\n    db: AsyncSession = Depends(get_db)\n):\n    # 1. Validate File if provided\n    if file:\n        if file.content_type not in ALLOWED_MIMES:\n            raise DomainException(\"Invalid file type. Only JPEG, PNG, and WebP are allowed.\", 400)\n        # Read to check size (in memory for now)\n        content = await file.read()\n        if len(content) > MAX_FILE_SIZE:\n            raise DomainException(\"File exceeds 5MB limit.\", 400)\n            \n    # 2. Sanitize and Validate URL\n    if not extracted_url:\n        raise DomainException(\"Extracted URL is empty\", 400)\n        \n    # Reject bad protocols strictly\n    bad_protocols = ['javascript:', 'data:', 'ftp:', 'file:', 'vbscript:']\n    lower_url = extracted_url.lower()\n    for bad in bad_protocols:\n        if lower_url.startswith(bad):\n            raise DomainException(f\"Unsafe protocol detected: {bad}\", 403)\n            \n    if not lower_url.startswith('http://') and not lower_url.startswith('https://'):\n        raise DomainException(\"Invalid protocol. Only HTTP and HTTPS are supported.\", 400)\n        \n    # 3. Store in History (Mock logic for now, real logic connects to DB)\n    scan = Scan(target=extracted_url, scan_type=\"QR\", status=\"pending\")\n    db.add(scan)\n    await db.commit()\n    await db.refresh(scan)\n    \n    return {\n        \"scan_id\": scan.id,\n        \"target\": extracted_url,\n        \"status\": \"success\",\n        \"message\": \"QR Code validated and analysis started.\"\n    }\n",
        "frontend/src/components/scanner/QRScanner.tsx": "import React, { useState } from 'react';\nimport CameraScanner from './CameraScanner';\nimport QRUploader from './QRUploader';\nimport ExtractionResult from './ExtractionResult';\nimport { motion } from 'framer-motion';\nimport { Camera, Upload } from 'lucide-react';\n\nconst QRScanner = () => {\n  const [mode, setMode] = useState<'camera' | 'upload'>('upload');\n  const [extractedUrl, setExtractedUrl] = useState<string | null>(null);\n\n  const handleSuccess = (url: string) => {\n    setExtractedUrl(url);\n  };\n\n  if (extractedUrl) {\n    return <ExtractionResult url={extractedUrl} onReset={() => setExtractedUrl(null)} />;\n  }\n\n  return (\n    <div className=\"max-w-2xl mx-auto glass-panel p-8\">\n      <div className=\"flex justify-center gap-4 mb-8\">\n        <button \n          onClick={() => setMode('upload')} \n          className={`flex items-center gap-2 px-6 py-3 rounded-lg font-medium transition ${mode === 'upload' ? 'bg-primary text-white' : 'bg-surface text-gray-400 hover:text-white'}`}\n        >\n          <Upload size={20} /> Upload Image\n        </button>\n        <button \n          onClick={() => setMode('camera')} \n          className={`flex items-center gap-2 px-6 py-3 rounded-lg font-medium transition ${mode === 'camera' ? 'bg-primary text-white' : 'bg-surface text-gray-400 hover:text-white'}`}\n        >\n          <Camera size={20} /> Camera\n        </button>\n      </div>\n      \n      <motion.div \n        key={mode}\n        initial={{ opacity: 0, x: mode === 'camera' ? 20 : -20 }}\n        animate={{ opacity: 1, x: 0 }}\n        transition={{ duration: 0.3 }}\n      >\n        {mode === 'camera' ? (\n          <CameraScanner onSuccess={handleSuccess} />\n        ) : (\n          <QRUploader onSuccess={handleSuccess} />\n        )}\n      </motion.div>\n    </div>\n  );\n};\n\nexport default QRScanner;\n",
        "frontend/src/components/scanner/CameraScanner.tsx": "import React, { useEffect, useRef, useState } from 'react';\nimport { Html5Qrcode } from 'html5-qrcode';\nimport { Loader2, AlertTriangle } from 'lucide-react';\n\nconst CameraScanner = ({ onSuccess }: { onSuccess: (url: string) => void }) => {\n  const [error, setError] = useState('');\n  const [loading, setLoading] = useState(true);\n  \n  useEffect(() => {\n    const html5QrCode = new Html5Qrcode(\"qr-reader\");\n    \n    html5QrCode.start(\n      { facingMode: \"environment\" },\n      { fps: 10, qrbox: { width: 250, height: 250 } },\n      (decodedText) => {\n        html5QrCode.stop();\n        onSuccess(decodedText);\n      },\n      (err) => {\n        // Ignore continuous stream errors\n      }\n    ).then(() => setLoading(false)).catch((err) => {\n      setError(\"Failed to access camera. Please ensure permissions are granted.\");\n      setLoading(false);\n    });\n\n    return () => {\n      if (html5QrCode.isScanning) {\n        html5QrCode.stop().catch(() => {});\n      }\n    };\n  }, [onSuccess]);\n\n  return (\n    <div className=\"w-full flex flex-col items-center\">\n      {error && (\n        <div className=\"bg-danger/10 border border-danger text-danger p-4 rounded-lg mb-4 flex items-center gap-2\">\n          <AlertTriangle size={20} /> {error}\n        </div>\n      )}\n      {loading && !error && (\n        <div className=\"flex flex-col items-center justify-center p-12\">\n          <Loader2 className=\"animate-spin text-primary w-12 h-12 mb-4\" />\n          <p className=\"text-gray-400\">Initializing Camera...</p>\n        </div>\n      )}\n      <div id=\"qr-reader\" className=\"w-full max-w-md overflow-hidden rounded-xl border-2 border-border shadow-2xl\"></div>\n    </div>\n  );\n};\n\nexport default CameraScanner;\n",
        "frontend/src/components/scanner/QRUploader.tsx": "import React, { useRef, useState } from 'react';\nimport { Html5Qrcode } from 'html5-qrcode';\nimport { UploadCloud, AlertCircle } from 'lucide-react';\n\nconst QRUploader = ({ onSuccess }: { onSuccess: (url: string) => void }) => {\n  const fileInputRef = useRef<HTMLInputElement>(null);\n  const [error, setError] = useState('');\n\n  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {\n    if (e.target.files && e.target.files.length > 0) {\n      const file = e.target.files[0];\n      if (file.size > 5 * 1024 * 1024) {\n        setError(\"File exceeds 5MB limit.\");\n        return;\n      }\n      \n      try {\n        const html5QrCode = new Html5Qrcode(\"hidden-qr-reader\");\n        const decodedText = await html5QrCode.scanFile(file, true);\n        onSuccess(decodedText);\n      } catch (err) {\n        setError(\"No valid QR code found in the image.\");\n      }\n    }\n  };\n\n  return (\n    <div className=\"text-center\">\n      {error && (\n        <div className=\"bg-danger/10 border border-danger text-danger p-4 rounded-lg mb-4 flex justify-center items-center gap-2\">\n          <AlertCircle size={18} /> {error}\n        </div>\n      )}\n      <div \n        className=\"border-2 border-dashed border-border hover:border-primary/50 transition bg-surface rounded-xl p-12 cursor-pointer flex flex-col items-center\"\n        onClick={() => fileInputRef.current?.click()}\n      >\n        <UploadCloud className=\"w-16 h-16 text-gray-500 mb-4\" />\n        <h3 className=\"text-xl font-bold mb-2\">Drag & Drop Image</h3>\n        <p className=\"text-gray-400 text-sm\">Supported formats: JPEG, PNG, WebP (Max 5MB)</p>\n        <input \n          type=\"file\" \n          ref={fileInputRef} \n          className=\"hidden\" \n          accept=\"image/jpeg, image/png, image/webp\"\n          onChange={handleFileChange}\n        />\n      </div>\n      <div id=\"hidden-qr-reader\" style={{ display: 'none' }}></div>\n    </div>\n  );\n};\n\nexport default QRUploader;\n",
        "frontend/src/components/scanner/ExtractionResult.tsx": "import React, { useState } from 'react';\nimport { motion } from 'framer-motion';\nimport { Link2, ShieldAlert, ShieldCheck, ArrowRight, RefreshCw, Loader2 } from 'lucide-react';\nimport api from '../../utils/axios';\nimport { useNavigate } from 'react-router-dom';\n\nconst ExtractionResult = ({ url, onReset }: { url: string; onReset: () => void }) => {\n  const [loading, setLoading] = useState(false);\n  const [error, setError] = useState('');\n  const navigate = useNavigate();\n\n  const handleAnalyze = async () => {\n    setLoading(true);\n    setError('');\n    try {\n      const formData = new FormData();\n      formData.append('extracted_url', url);\n      \n      const res = await api.post('/scan/qr', formData);\n      // Navigate to results page after analysis triggers successfully\n      navigate(`/app/results/${res.data.scan_id}`);\n    } catch (err: any) {\n      setError(err.response?.data?.error || \"Failed to trigger analysis. The URL may be fundamentally invalid or unsafe.\");\n      setLoading(false);\n    }\n  };\n\n  const isSuspicious = url.toLowerCase().includes('javascript:') || !url.startsWith('http');\n\n  return (\n    <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} className=\"text-center space-y-6\">\n      <div className={`w-20 h-20 mx-auto rounded-full flex items-center justify-center ${isSuspicious ? 'bg-danger/20 text-danger' : 'bg-success/20 text-success'}`}>\n        {isSuspicious ? <ShieldAlert size={40} /> : <ShieldCheck size={40} />}\n      </div>\n      \n      <div>\n        <h2 className=\"text-2xl font-bold mb-2\">Extracted Payload</h2>\n        <div className=\"bg-surface border border-border rounded-lg p-4 break-all flex items-center gap-3\">\n          <Link2 className=\"shrink-0 text-gray-500\" />\n          <span className=\"text-lg font-mono text-white\">{url}</span>\n        </div>\n      </div>\n\n      {error && (\n        <div className=\"bg-danger/10 border border-danger text-danger p-4 rounded-lg text-sm text-left\">\n          {error}\n        </div>\n      )}\n\n      <div className=\"flex flex-col sm:flex-row gap-4 pt-4\">\n        <button onClick={onReset} disabled={loading} className=\"btn-secondary flex-1 flex items-center justify-center gap-2\">\n          <RefreshCw size={18} /> Scan Another\n        </button>\n        <button onClick={handleAnalyze} disabled={loading} className=\"btn-primary flex-1 flex items-center justify-center gap-2\">\n          {loading ? <Loader2 className=\"animate-spin\" size={18} /> : <>Analyze Payload <ArrowRight size={18} /></>}\n        </button>\n      </div>\n    </motion.div>\n  );\n};\n\nexport default ExtractionResult;\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("Stage 6 Scaffolded.")
